```class Solution:
    def maxSubstrings(self, word: str) -> int:
        n = len(word)
        ans = 0
        for i in range(n):
            for j in range(i + 3, n):
                if word[i] == word[j]:
                    k = i + 1
                    while k < j and word[k] == word[i]:
                        k += 1
                    if k == j:
                        ans += 1
        return ans
